INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 8, "東山奈央", "人助けが大好き！　前向き格闘娘", "トゥインクルウィッシュ", "人助け、応援", 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ", 0, 2, 100101, "獣人族", 155, "A", 44);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 4, "種田梨沙", "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", "料理、人間観察", 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ", 0, 2, 100201, "ヒューマン", 158, "O", 47);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 1, "早見沙織", "クールで何事にも真っ直ぐな剣士", "トゥインクルウィッシュ", "読書、乗馬、お茶", 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ", 0, 2, 100301, "魔族", 163, "B", 46);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (9, 8, "諸星すみれ", "探検好きのイタズラっ子", "リトルリリカル", "いたずら、探検", 10, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", "ミソギ", 0, 5, 100401, "ヒューマン", 128, "O", 27);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 11, "下田麻美", "ヒーローに憧れる騎士見習いの少女", "王宮騎士団（NIGHTMARE）", "ヒーローごっこ", 25, "？？？", "マツリ", 0, 8, 100501, "獣人族", 146, "O", 40);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 11, "浅倉杏美", "甘え上手なみんなの人気者", "悪魔偽王国軍（ディアボロス）", "サックス", 22, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", "アカリ", 0, 7, 100601, "魔族", 150, "O", 42);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 1, "雨宮天", "プリン大好きゴースト娘", "悪魔偽王国軍（ディアボロス）", "プリンを食べること", 23, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "ミヤコ", 0, 7, 100701, "魔族", 130, "B", 32);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 10, "大空直美", "ボクは誰よりも美しい", "ヴァイスフリューゲル　ランドソル支部", "鏡で自分を見ること", 10, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ユキ", 0, 15, 100801, "エルフ", 150, "AB", 40);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 7, "髙野麻美", "前世を信じる中二病患者、「疾風の冥姫」", "トワイライトキャラバン", "小説執筆", 5, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", "アンナ", 0, 13, 100901, "魔族", 159, "A", 45);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 9, "内田真礼", "マホマホ王国のプリンセス", "自警団（カォン）", "空想、ぬいぐるみ集め", 22, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホ", 0, 10, 101001, "獣人族", 155, "O", 42);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 8, "阿澄佳奈", "人懐っこくてマシンガントークな妹系少女", "ラビリンス", "お裁縫", 25, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", "リノ", 0, 3, 101101, "ヒューマン", 156, "A", 44);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 12, "大橋彩香", "みんなのために超能力を使う眠り姫", "フォレスティエ", "妹と遊ぶこと、二度寝、昼寝、早寝", 24, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", "ハツネ", 0, 6, 101201, "エルフ", 156, "A", 46);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 8, "佳村はるか", "オタク全開な魔法少女", "トワイライトキャラバン", "読書、魔法", 21, "", "ナナカ", 0, 13, 101301, "魔族", 166, "O", 55);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 11, "水瀬いのり", "頭脳明晰な美少女名探偵", "自警団（カォン）", "読書、推理", 3, "test", "カスミ", 0, 10, 101401, "獣人族", 152, "AB", 41);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (21, 9, "國府田マリ子", "母性溢れる優しいみんなの「ミサト先生」", "フォレスティエ", "絵本作り", 5, "test", "ミサト", 0, 6, 101501, "エルフ", 165, "O", 54);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 4, "上坂すみれ", "天真爛漫で人気者のカリスマモデル", "ルーセント学院", "ファッション", 10, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", "スズナ", 0, 14, 101601, "魔族", 167, "O", 48);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 7, "高森奈津美", "いつでも「なんくるないさ～」な天然娘", "自警団（カォン）", "踊り、空手", 7, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", "カオリ", 0, 10, 101701, "獣人族", 158, "A", 53);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (23, 8, "伊藤静", "多くの男性を魅了する無垢な女教師", "ルーセント学院", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", "イオ", 0, 14, 101801, "魔族", 162, "B", 52);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (10, 4, "日高里菜", "お歌もにんじんも、ウサギさんも大好き♪", "リトルリリカル", "かわいいもの集め", 3, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", "ミミ", 0, 5, 102001, "獣人族", 117, "O", 21);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 6, "植田佳奈", "泣き虫で臆病な守ってあげたい女の子", "サレンディア救護院", "観劇、おままごと", 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "クルミ", 0, 9, 102101, "ヒューマン", 150, "B", 40);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 11, "原紗友里", "人見知りであまのじゃくな女の子", "悪魔偽王国軍（ディアボロス）", "ゲーム全般", 22, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", "ヨリ", 0, 7, 102201, "魔族", 150, "O", 40);
