INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 12, "悠木碧", "お嬢さまのためにがんばるドジっ娘メイド", "サレンディア救護院", "ご奉仕", 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "スズメ", 0, 9, 102501, "ヒューマン", 154, "O", 43);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 1, "小岩井ことり", "遊びと睡眠が何より大事なぐうたら娘", "牧場（エリザベスパーク）", "あんパン", 1, "test", "リン", 0, 11, 102601, "獣人族", 144, "B", 42);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 7, "橋本ちなみ", "運命の相手に一途すぎる乙女", "トワイライトキャラバン", "実験、裁縫、料理", 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "エリコ", 0, 13, 102701, "魔族", 154, "B", 43);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 10, "堀江由衣", "救護院を経営する優しい庶民派お嬢様", "サレンディア救護院", "経営、お茶会", 4, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", "サレン", 0, 9, 102801, "エルフ", 156, "A", 43);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 1, "日笠陽子", "歌って踊れる大人気アイドル", "カルミナ", "舞台鑑賞、ダンス", 24, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", "ノゾミ", 0, 4, 102901, "ヒューマン", 157, "B", 40);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 8, "佐藤聡美", "トーゴクの神秘、オシエテクダサイ！", "ヴァイスフリューゲル　ランドソル支部", "忍法開発", 31, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ニノン", 0, 15, 103001, "ヒューマン", 163, "O", 51);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 12, "大坪由佳", "占いが得意な霊能少女", "悪魔偽王国軍（ディアボロス）", "占い", 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "シノブ", 0, 7, 103101, "魔族", 157, "AB", 42);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 3, "松嵜麗", "一人前の商人を目指すパワフルお嬢様", "メルクリウス財団", "慈善事業", 12, "この私とともにいる限り、\nお金に不自由はさせませんわ！", "アキノ", 0, 12, 103201, "ヒューマン", 157, "AB", 45);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (20, 3, "新田恵海", "みんなを笑顔にするお笑い牧場主", "牧場（エリザベスパーク）", "漫才", 3, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", "マヒル", 0, 11, 103301, "ヒューマン", 142, "B", 35);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (22, 3, "今井麻美", "純情でほっとけない大人の女性", "メルクリウス財団", "ウインドーショッピング", 16, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", "ユカリ", 0, 12, 103401, "エルフ", 164, "A", 55);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (8, 2, "小倉唯", "礼儀正しくしっかり者のちびっ子優等生", "リトルリリカル", "お勉強", 2, "test", "キョウカ", 0, 5, 103601, "エルフ", 118, "A", 21);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 8, "茅原実里", "義理堅くてからかい好きな剣術少女", "王宮騎士団（NIGHTMARE）", "剣術、年長者をからかう", 11, "test", "トモ", 0, 8, 103701, "ヒューマン", 149, "A", 43);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 11, "小清水亜美", "読書が趣味の病弱少女", "牧場（エリザベスパーク）", "読書、お散歩", 3, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", "シオリ", 0, 11, 103801, "獣人族", 153, "A", 40);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (13, 6, "花澤香菜", "「友達」に憧れる、エルフの森の女の子", "フォレスティエ", "友達作りのイメトレ", 6, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", "アオイ", 0, 6, 104001, "エルフ", 158, "AB", 44);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 6, "福原綾香", "人々を守るために歌う、唱喚士の少女", "カルミナ", "各種楽器", 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "チカ", 0, 4, 104201, "ヒューマン", 163, "O", 46);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 8, "小松未可子", "男勝りで情に厚いワイルド娘", "自警団（カォン）", "お菓子作り", 9, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", "マコト", 0, 10, 104301, "獣人族", 168, "O", 54);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES ("??", 5, "丹下桜", "かつては夜を支配した最強の吸血鬼", "悪魔偽王国軍（ディアボロス）", "世界征服", 5, "test", "イリヤ", 0, 7, 104401, "魔族", 172, "A", 50);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 11, "長妻樹里", "妄想大好き！　ほんとは照れ屋な女の子", "ヴァイスフリューゲル　ランドソル支部", "小説を読むこと", 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "クウカ", 0, 15, 104501, "ヒューマン", 157, "AB", 49);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, 3, "沼倉愛美", "弱きを助け強きをくじく猫娘", "メルクリウス財団", "猫とたわむれること", 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "タマキ", 0, 12, 104601, "獣人族", 158, "AB", 48);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (25, 10, "川澄綾子", "素顔を見せない冷静沈着な女性騎士", "王宮騎士団（NIGHTMARE）", "格闘技、湯浴み", 25, "？？？", "ジュン", 0, 8, 104701, "ヒューマン", 171, "A", 50);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (20, 11, "田所あずさ", "仕事も私事も効率優先な傭兵少女", "メルクリウス財団", "傭兵などのアルバイト", 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "ミフユ", 0, 12, 104801, "ヒューマン", 163, "O", 49);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 10, "生天目仁美", "お姉ちゃんがお世話してあげるからねっ！", "ラビリンス", "家事全般", 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "シズル", 0, 3, 104901, "ヒューマン", 168, "O", 54);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 1, "久野美咲", "ちょっとおませな恋に恋する女の子", "ルーセント学院", "ファッション誌鑑賞、コスメ集め", 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ミサキ", 0, 14, 105001, "魔族", 120, "A", 22);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (27, 3, "三石琴乃", "実験が趣味の危険な科学者", "トワイライトキャラバン", "研究、実験", 7, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", "ミツキ", 0, 13, 105101, "ヒューマン", 166, "A", 53);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 3, "徳井青空", "乙女チックなもふもふアニマル", "牧場（エリザベスパーク）", "毛繕い、お喋り", 14, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", "リマ", 0, 11, 105201, "獣人族", 150, "A", 100);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 7, "辻あゆみ", "見た目も中身もお子ちゃまな異国の軍人", "ヴァイスフリューゲル　ランドソル支部", "お菓子屋通い", 28, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", "モニカ", 0, 15, 105301, "ヒューマン", 140, "A", 33);
