INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 3, "金元寿子", "空への冒険を夢見る騎空士の少女", "？？？", "冒険、おしゃべり", 10, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", "ジータ", 0, "", 105701, "ヒューマン", 156, "O", 45);
