INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (15, 12, "悠木碧", "お嬢さまのためにがんばるドジっ娘メイド", "サレンディア救護院", "ご奉仕", 12, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", "スズメ（サマー）", 0, 9, 107701, "ヒューマン", 154, "O", 43);
