INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (19, 3, "沼倉愛美", "弱きを助け強きをくじく猫娘", "メルクリウス財団", "猫とたわむれること", 1, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", "タマキ（サマー）", 0, 12, 107901, "獣人族", 158, "AB", 48);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (20, 11, "田所あずさ", "仕事も私事も効率優先な傭兵少女", "メルクリウス財団", "傭兵などのアルバイト", 11, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", "ミフユ（サマー）", 0, 12, 108001, "ヒューマン", 163, "O", 49);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 12, "大坪由佳", "占いが得意な霊能少女", "悪魔偽王国軍（ディアボロス）", "占い", 22, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", "シノブ（ハロウィン）", 0, 7, 108101, "魔族", 157, "AB", 42);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 1, "雨宮天", "プリン大好きゴースト娘", "悪魔偽王国軍（ディアボロス）", "プリンを食べること", 23, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", "ミヤコ（ハロウィン）", 0, 7, 108201, "魔族", 130, "B", 32);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (11, 1, "久野美咲", "ちょっとおませな恋に恋する女の子", "ルーセント学院", "ファッション誌鑑賞、コスメ集め", 3, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", "ミサキ（ハロウィン）", 0, 14, 108301, "魔族", 120, "A", 22);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 6, "福原綾香", "人々を守るために歌う、唱喚士の少女", "カルミナ", "各種楽器", 3, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", "チカ（クリスマス）", 0, 4, 108401, "ヒューマン", 163, "O", 46);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (12, 6, "植田佳奈", "泣き虫で臆病な守ってあげたい女の子", "サレンディア救護院", "観劇、おままごと", 9, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", "クルミ（クリスマス）", 0, 9, 108501, "ヒューマン", 150, "B", 40);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 5, "芹澤優", "ぷうきちといつも一緒！", "サレンディア救護院", "屋内でできる遊び", 10, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", "アヤネ（クリスマス）", 0, 9, 108601, "ヒューマン", 148, "B", 38);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 8, "東山奈央", "人助けが大好き！　前向き格闘娘", "トゥインクルウィッシュ", "人助け、応援", 27, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", "ヒヨリ（ニューイヤー）", 0, 2, 108701, "獣人族", 155, "A", 44);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 4, "種田梨沙", "戦闘のサポートが得意な、心優しい少女", "トゥインクルウィッシュ", "料理、人間観察", 5, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", "ユイ（ニューイヤー）", 0, 2, 108801, "ヒューマン", 158, "O", 47);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 1, "早見沙織", "クールで何事にも真っ直ぐな剣士", "トゥインクルウィッシュ", "読書、乗馬、お茶", 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ（ニューイヤー）", 0, 2, 108901, "魔族", 163, "B", 46);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 7, "橋本ちなみ", "運命の相手に一途すぎる乙女", "トワイライトキャラバン", "実験、裁縫、料理", 30, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", "エリコ（バレンタイン）", 0, 13, 109001, "魔族", 154, "B", 43);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 10, "生天目仁美", "お姉ちゃんがお世話してあげるからねっ！", "ラビリンス", "家事全般", 24, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", "シズル（バレンタイン）", 0, 3, 109101, "ヒューマン", 168, "O", 54);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 12, "日笠陽子", "英霊と契約を結んだマナリアの天才王女", "？？？", "読書", 1, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", "アン", 0, "", 109201, "ヒューマン", 156, "AB", 55);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 2, "こやまきみこ", "マナリア魔法学院の新入生", "？？？", "食べること、眠ること", 4, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", "ルゥ", 0, "", 109301, "ヒューマン", 144, "O", 45);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 11, "福原綾香", "人を超越した力を有す心優しい竜姫", "？？？", "ピアノ", 3, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", "グレア", 0, "", 109401, "半人半竜", 167, "B", 67);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 11, "長妻樹里", "妄想大好き！　ほんとは照れ屋な女の子", "ヴァイスフリューゲル　ランドソル支部", "小説を読むこと", 19, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", "クウカ（オーエド）", 0, 15, 109501, "ヒューマン", 157, "AB", 49);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 8, "佐藤聡美", "トーゴクの神秘、オシエテクダサイ！", "ヴァイスフリューゲル　ランドソル支部", "忍法開発", 31, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", "ニノン（オーエド）", 0, 15, 109601, "ヒューマン", 163, "O", 51);
INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (17, 2, "水瀬いのり", "鬼がかりの万能妹メイド", "？？？", "演劇鑑賞、詩文", 2, "", "レム", 0, "", 109701, "鬼族", 154, "?", "??");
