INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (16, 9, "内田真礼", "マホマホ王国のプリンセス", "自警団（カォン）", "空想、ぬいぐるみ集め", 22, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", "マホ（シンデレラ）", 0, 10, 116001, "獣人族", 155, "O", 42);
