INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (14, 10, "大空直美", "ボクは誰よりも美しい", "ヴァイスフリューゲル　ランドソル支部", "鏡で自分を見ること", 10, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", "ユキ（オーエド）", 0, 15, 117601, "エルフ", 150, "AB", 40);
