INSERT INTO `v1_407dd5506ad0eed60a88211bc753716b511e8a4d02af4a00a84bad0073ab8aab` VALUES (18, 1, "早見沙織", "クールで何事にも真っ直ぐな剣士", "トゥインクルウィッシュ", "読書、乗馬、お茶", 12, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", "レイ（アストラル）", 0, 17, 928801, "魔族", 163, "B", 46);
